powerpagecomponent.content:
{
  "description": "Used in determining whether commission approvals are enabled for a particular period. The value in /NumApprovalPeriods is SUBTRACTED from the period number of the MOST RECENT period. Given that the most recent period has period number R, then for any particular period number X, approvals are enabled if X >= (R - NumApprovalPeriods). So by default, ONLY the most recent period will be enabled for approvals",
  "source": 0,
  "value": "0"
}
